-- portal-a31: agregados historicos L3 sobre TODAS las fotos vigentes + mayor vivo (passthrough del
-- jsonb). Sin parametros. sin_datos:true lo decide la funcion.
SELECT cuenta_corriente_historico_acumulados() AS acumulados;

