// ===== portal-a31-cuenta-corriente-historico-acumulados__TEST — render JSON (acumulados L3) =====
// Passthrough del jsonb de cuenta_corriente_historico_acumulados (6 claves top-level: sin_datos, piso,
// totales, evolucion, saldos_por_socio, meta). Read-only. sin_datos:true es ok:true (NUNCA no_encontrado,
// D-C-47); solo un jsonb con 'error' se surfacea como error_interno (defensivo; no ocurre en la practica,
// la funcion no toma parametros). No se inventan defaults ni se renombran claves.
function safeAll(nodeName) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    return { ok: true, rows: items.map(it => it.json) };
  } catch (e) { return { ok: false, rows: [] }; }
}

const r = safeAll('PG: leer acumulados');
if (!r.ok || r.rows.length === 0) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar los acumulados', detail: null } } }];
}

const acumulados = r.rows[0].acumulados;
if (acumulados && acumulados.error) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: String(acumulados.error), detail: null } } }];
}

return [{ json: { ok: true, data: acumulados } }];
